var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……하아, 제길.","JPN":"……はあ、くそ。","ENG":"...*Sigh.* Bollocks.","TWN":"……哀，該死。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"로이?","JPN":"ロイ？","ENG":"Roy?","TWN":"羅伊？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"집에 안 들어가고 여기서 뭘 하고 있지?","JPN":"家に入らないで、何をしているんだ？","ENG":"What are you doing here? Aren't you supposed to be home?","TWN":"你怎麼不進門？站在外面幹什麼呢？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 할배였어?","JPN":"なんだ、ジジイか？","ENG":"Oh, Gramps, it's you.","TWN":"什麼啊，原來是爺爺啊？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"왔으면 진작 연락하지 그랬어?","JPN":"来てたのなら連絡しろよ。","ENG":"You could've told me if you were here.","TWN":"既然來了怎麼不早點聯繫我？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 또 빈손인 거야? 이번 낚시도 종쳤나 봐?","JPN":"で、また手ぶら？　今日の釣りもダメだったようだな。","ENG":"So, you're empty-handed again? Guess the fishing was a bust then, eh?","TWN":"所以又是兩手空空嗎？看來這次也沒釣成？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"쯧, 녀석 말버릇하고는……. 원래 낚시는 낚을 때까지 하는 거다.","JPN":"チッ、なんて口の利き方を……元々釣りは釣れるまでやるものだ。","ENG":"Tsk. You and your filthy mouth... You're supposed to fish until you catch something.","TWN":"嘖，你這傢伙說話的口氣可真……釣魚本來就是要釣到魚為止的。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"오늘 못 잡았다고 실망할 것 없어. 내일은 잡을 수 있을 거라고 믿는 게 중요하니까.","JPN":"今日釣れなかったとして、がっかりする必要はない。明日は釣れると信じることが大切だからな。","ENG":"No need to be disappointed for not catching anything today. Believing that you can catch one the next day is what's important.","TWN":"不要因為今天沒抓到就感到失望，因為相信明天能抓到才是重要的。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"맨날 말은 그렇게 하고서 한 마리도 못 잡는데 무슨.","JPN":"いつもそう言って一匹も釣れてないじゃないか。","ENG":"You always say that, but you never even caught one.","TWN":"每天都那麼說，卻一條都抓不到。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할배가 자랑하던 특제 <color=#ffd34c>피시 앤 칩스</color>는 언제 맛볼 수 있는 건데?","JPN":"ジジイ自慢の特製<color=#ffd34c>フィッシュアンドチップス</color>には、いつありつけるんだ？","ENG":"When can I try your special <color=#ffd34c>fish and chips</color> you always talk about?","TWN":"到底什麼時候能嘗到爺爺一直引以為傲的特製<color=#ffd34c>炸魚薯條</color>啊？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"후후. 왜? 동네 하수도에서 배스라도 낚아다 줄까.","JPN":"ふふ。なんだ？　街の下水道でバスでも釣ってやろうか。","ENG":"Hah hah. Why, would you like me to catch a bass from a nearby sewers?","TWN":"呵呵，怎麼？要不在附近的下水道裡給你釣個鱸魚？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"으엑, 됐거든? 할배나 많이 해 드셔!","JPN":"げっ、いらねぇよ。一人で食べろよ！","ENG":"Ugh, forget it! You can keep it all to yourself!","TWN":"呃，算了吧！還是留給你自己吃吧！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 얼굴은 왜 그 모양이지? 혹시 누구한테 맞고 다니는 거냐?","JPN":"それで、その顔はどうした？　もしかして、誰かに殴られたのか？","ENG":"So, what's happened to your face? Are you being bullied?","TWN":"臉怎麼了？不會是被誰打了吧？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"딱히. 할배가 신경 쓸 일은 아니야.","JPN":"別に。ジジイが気にすることじゃない。","ENG":"Not really. It's none of your concern.","TWN":"不是，不用爺爺你操心。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"로버트 짓이냐?","JPN":"ロバートか？","ENG":"Was it Robert?","TWN":"是羅伯特幹的嗎？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래! 그 망할 아버지한테 들이 받았다! 왜!","JPN":"そうだよ！　あのクソ親父とケンカした！　文句あるのか！？","ENG":"Yeah! I tackled him, so what?!","TWN":"沒錯！我頂撞了那個糟糕爸爸！怎樣！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 자식이 자꾸 술 먹고, 엄마를 때리려고 하잖아! 이제 됐어?","JPN":"あいつが酔っぱらって、お母さんを殴ろうとするからだ！　これで満足か？","ENG":"That bastard keeps drinking and trying to hit Mum! You happy?","TWN":"那傢伙老是喝酒，還想打媽媽呢！行了吧？！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 또 미안하다고 할 거면, 그냥 아무 말도 하지 마.","JPN":"ったく。またあの時みたいに、謝ったりするんじゃねぇぞ。","ENG":"Blimey. If you're going to apologize, keep it to yourself.","TWN":"真是，如果你又要和我說對不起，還是什麼都別說了吧。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어차피 할배 잘못 아닌 거 알고 있으니까.","JPN":"ジジイのせいじゃないってことくらい、わかってるし。","ENG":"I know it's not your fault anyway.","TWN":"反正我知道這不是你的錯。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 망할 집구석, 당신이 부쳐주는 돈 아니었으면 진작 다 쫄쫄 굶어 죽었어.","JPN":"こんなボロ家、あなたが送ってくれるお金がなかったら、とっくにみんな飢え死にしてたんだ。","ENG":"This bloody family would've starved to death if it weren't for the money you sent us.","TWN":"這個破地方，要不是爺爺你寄的錢，我們早就都餓死了。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 이제 와서 괜히 신경 써주는 척하지 말고, 친구들이랑 낚시나 실컷 다니라고.","JPN":"だから俺らのことは気にしないで、友達と釣りでも楽しんでてくれ。","ENG":"So, don't act like you care about us after everything. Just go fishing with your friends or something.","TWN":"所以你別現在才來裝出一副關心的樣子，還是跟大家釣魚去吧。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아버지를 때려 눕히든, 엄마를 떼어 놓든 내가 어떻게든 할 테니깐.","JPN":"親父を殴り飛ばすにしろ、お母さんから引き離すにしろ、俺がなんとかするから。","ENG":"I'll take care of it. Whether I knock down Dad or I separate Mum from him.","TWN":"不管是打倒我爸爸，還是帶媽媽離開這裡，我都自己會想辦法的。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 네 말이 맞다.","JPN":"ああ、お前の言うとおりだ。","ENG":"You're right.","TWN":"沒錯，你說的對。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"어떤 대의명분을 댄다 해도, 내가 너희 가족을 신경 쓰지 못한 건 사실이야.","JPN":"どんな大義名分も言い訳にならない。俺がお前の家族を見過ごしてきたのは事実だ。","ENG":"I can say it was for a noble cause, but it's still true that I wasn't able to take care of your family.","TWN":"不管雖然家人。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 와서…… 그 깊은 감정의 골을 해결하는 건 불가능하겠지.","JPN":"今更……その深い心の溝を埋めることは不可能だろう。","ENG":"And... it would be impossible to fill that deep of an emotional void now.","TWN":"事到如今……才來解決那早已破裂的感情是不可能的。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};